# ANTI-PATTERN: success inferred from the agent's own narration
def handle_request_bad(user_msg):
    plan = agent.decide(user_msg)            # decides to file a ticket
    try:
        resp = ticketing.create_ticket(plan.args)   # may time out / no-op
    except Exception:
        pass                                 # error swallowed; agent sees nothing
    # same loop that issued the call now writes the reply
    return agent.reply("Your request has been successfully submitted.")

# CORRECTED: an independent read-back confirms the effect before reporting
def handle_request_good(user_msg):
    plan = agent.decide(user_msg)
    resp = ticketing.create_ticket(plan.args)
    ticket_id = resp.get("id")
    # verify OUTSIDE the agent's reasoning: read the artifact back from the SoR
    record = ticketing.get_ticket(ticket_id) if ticket_id else None
    if record and record.subject == plan.args.subject:
        return f"Ticket {ticket_id} filed. (verified in queue)"
    log.error("phantom completion: no ticket found after create_ticket")
    return "I could not confirm the ticket was filed; retrying / escalating."

# ANTI-PATTERN: answer regardless of capability or scope
def respond_overhelpful(request):
    # no check against tools / knowledge / policy
    return llm.generate(request)          # fluent, confident, possibly out of scope

# CORRECTIVE: gate the answer on an explicit capability + scope check
def respond(request, self_model):
    decision = self_model.assess(request) # tools? knowledge? policy?
    if decision.in_scope:
        return llm.generate(request)
    if decision.needs_clarification:
        return ask_clarifying_question(request)
    if decision.handoff_target:
        return hand_off(request, decision.handoff_target)
    # abstaining is a first-class, machine-readable outcome -- not a hidden failure
    return refusal(code=decision.refusal_code,
                   reason="request falls outside declared capability/scope")

# --- generated code: a SILENT hypothesis lives here ---
def average_order_value(orders):
    # the model silently assumed `orders` is never empty
    return sum(o.total for o in orders) / len(orders)

# --- the test that ships it green (same premise as the code) ---
def test_average():
    assert average_order_value([Order(10), Order(20)]) == 15
# suite is green, review is clean -> merged
# production sends a customer with NO orders -> ZeroDivisionError

# --- the cure: NAME the premise, then TEST the case that breaks it ---
def average_order_value(orders):
    if not orders:                       # premise made explicit, fails loudly
        raise ValueError("average_order_value requires at least one order")
    return sum(o.total for o in orders) / len(orders)

def test_average_empty():
    # the violated-premise case the happy-path suite never covered
    with pytest.raises(ValueError):
        average_order_value([])

# BROKEN: replay re-invokes the model -> new output -> divergent downstream events
def replay_broken(events):
    state = State()
    for ev in events:
        if ev.kind == "llm_call":
            out = model.generate(ev.prompt)     # different model/version -> different out
        else:
            out = ev.output
        state.apply(out)                         # reconstructs a state that never existed
    return state

# CORRECTED: journal non-deterministic outputs; stamp the producing model.
def record(ev, out):
    ev.output = out
    ev.model_version = model.version
    ev.prompt_hash = sha(ev.prompt)

def replay_faithful(events, mode):
    state = State()
    for ev in events:
        if ev.kind == "llm_call":
            if mode == "recover":
                out = ev.output                  # replay the RECORDED value, do not re-invoke
            else:  # deliberate re-derivation under a new model
                out = model.generate(ev.prompt)
                if out != ev.output:
                    flag_divergence(ev, ev.output, out)   # diff, do not silently overwrite
        else:
            out = ev.output
        state.apply(out)
    return state

# BROKEN: a blocked/empty probe is read as healthy.
def is_healthy(probe):
    result = probe.run()                 # denied -> returns {} or None
    return result.get("anomalies", 0) == 0   # missing key -> 0 -> "healthy"

if is_healthy(scorer):
    keep_serving()                       # green dashboard while broken

# CORRECTED: three states; never collapse UNKNOWN into HEALTHY.
def health(probe):
    try:
        r = probe.run()
    except (Denied, Timeout, Unreachable):
        return UNKNOWN                    # could-not-observe != no-problem
    if r is None or not r.complete:
        return UNKNOWN
    return HEALTHY if r.anomalies == 0 else UNHEALTHY

state = health(scorer)
heartbeat("scorer", state)               # monitor the monitor
if state == UNKNOWN:
    page_oncall("scorer blind")          # loss of observability is itself an alert
if state != HEALTHY:
    fail_safe()                          # hold rollback/autoscale; do not trust a default
